var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"우습군요, 방해자.","JPN":"滑稽ですね、邪魔者。","ENG":"How amusing, Disturber.","TWN":"真是可笑，妨礙者。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"가아그셰블라는 신성 정보 집합체…….","JPN":"ガアグシェブラは神聖情報集合体……","ENG":"Gha'agsheblah is a Divinity collection of information...","TWN":"加格舍夫拉是神性情報集合體……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"고작 저희 중에 일부에 불과했던 당신이 저희를 탐식할 수 있다고 생각하나요?","JPN":"我々の一部に過ぎなかったあなたが、我々を貪食できると思いますか？","ENG":"Did you really think someone who was merely a fragment of us could devour us?","TWN":"不過只是我們的一部分，你以為能吞噬我們嗎？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아하하, 글쎄요?","JPN":"あはは、どうでしょう？","ENG":"Ahaha, who knows?","TWN":"哈哈哈，誰知道呢？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"혼자서는 조금 힘들지도 모르겠지만, 저는 혼자가 아닌 걸요?","JPN":"一人では少し心もとないかもしれませんけど……一人じゃありませんよ、私。","ENG":"On my own it might be a little difficult, but I am not alone, you see?","TWN":"一個人的話，或許有點勉強，但我可不是孤單一人。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"우리의 숙적이었던 기사님께서 함께하니까요!","JPN":"我々の宿敵だった騎士様が一緒ですから！","ENG":"After all, our former nemesis, my knight, is with me!","TWN":"因為曾是我們宿敵的騎士，要與我並肩作戰！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"끌어내려주지, 마이트너.","JPN":"引きずり下ろしてやろう、マイトナー。","ENG":"I'll drag you down, Meitner.","TWN":"我會把你拉下來，邁特納。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"심연의 밑바닥까지……!","JPN":"深淵の底まで……！","ENG":"All the way to the very bottom of the abyss...!","TWN":"直到深淵的最底層……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"큿, 예나 지금이나, 정말로 끈질긴 사슬이로군요……!","JPN":"くっ、昔も今も、なんてしつこい鎖……！","ENG":"Kgh, whether then or now, those chains really are tenacious...!","TWN":"嘖，無論過去還是現在，真是頑強的鎖鏈啊……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈도 잘 알고 있을 텐데?","JPN":"貴様もわかっているだろう。","ENG":"You know it yourself, don't you?","TWN":"你自己也很清楚吧？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이 사슬은 오직 네놈들을 묶어두기 위해 방패에서 벼려진 무장이라는 것을.","JPN":"この鎖は貴様らを縛りつけるためだけに盾から作られた武装。","ENG":"These chains are weapons forged from a shield solely to bind the likes of you.","TWN":"這條鎖鏈，正是為了束縛你們而自盾牌中鍛造的武裝。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"방패를 잃은 내가 이걸 쓸 수 있다는 건, 애초부터 이럴 운명이었다는 뜻이겠지!","JPN":"盾を失った俺がこれを扱えるということは、最初からこうなる運命だと決まっていたのだろう！","ENG":"The fact that I can wield them even after losing my shield means this was fate from the start!","TWN":"失去盾牌的我還能使用它，從一開始就注定會變成這樣吧！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그렇다면 수백 번이든, 수천 번이든 얽매여주마, 마이트너.","JPN":"ならば数百回でも、数千回でもその運命を受け入れてやろう。マイトナー。","ENG":"If that's the case, I'll bind you hundreds, even thousands of times, Meitner.","TWN":"既然如此，不管是幾百、幾千次，我都會纏住你們，邁特納。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈들의 그 잘난 신성 파편을 전부 소모─────","JPN":"貴様らのその神聖の破片とやらを全部消耗させ─────","ENG":"Until every last one of your precious Divinity Fragments is completely spent────","TWN":"把你們引以為傲的神性碎片全部消耗殆盡─────"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 기사를 먼저 처리하는 겁니다.","JPN":"エデル、先に騎士を仕留めるのです。","ENG":"Edel, deal with the Knight first.","TWN":"艾瑟兒，先處理騎士。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_ICE_GRA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"봉인 사슬이 없다면, 당신이 방해자를 쓰러트리는 건 어렵지 않을 거예요.","JPN":"封印の鎖さえなければ、あなたが邪魔者を倒すことなど造作もないはずですわ。","ENG":"Without the Sealing Chains, defeating the Disturber won't be difficult for you.","TWN":"沒有封印鎖鏈的話，你要擊倒妨礙者並不困難。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_ICE_GRA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"레지나, 제가 충고드렸을 텐데요?","JPN":"レジーナ、忠告したはずですよ？","ENG":"Regina, did I not warn you?","TWN":"蕾佳娜，我應該警告過你吧？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"시간을 얼리는 건, 신중하게 생각해야 한다고요?","JPN":"時間を凍結させるのは、慎重にやるべきだと。","ENG":"That freezing time is something you should consider very carefully.","TWN":"凍結時間這件事必須慎重考慮。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"레지나 님……!?","JPN":"レジーナ様……！？","ENG":"Miss Regina...?!","TWN":"蕾佳娜大人……！？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아무리 학회장이라고 해도, 당신은 결국 연약한 인간이랍니다.","JPN":"学会長といっても、あなたは所詮脆弱な人間。","ENG":"No matter if you are the President, you are still a fragile human in the end.","TWN":"就算你是學會長，終究也只是脆弱的人類。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"마왕의 위계를 이은 존재를 대적할 수 있을 리 없어요.","JPN":"魔王の位階を引き継いだ存在と張り合えるわけがありません。","ENG":"There is no way you can oppose one who inherited a Demon Lord's hierarchy.","TWN":"不可能與繼承魔王位階的存在抗衡。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그리고 이 싸움에서 어머니는 그런 당신을 지켜가면서 싸우고 있죠.","JPN":"そしてこの戦いでお母さんはそんなあなたを守りながら戦っています。","ENG":"And in this fight, Mother is protecting someone like you while she battles.","TWN":"而在這場戰鬥中，母親一邊保護你、一邊戰鬥。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"이런 상황에서 학회장이 시간을 멈추면…….","JPN":"こんな状況で学会長が時間を止めたら……","ENG":"In a situation like this, if the President freezes time...","TWN":"在這種情況下，若學會長停止時間……"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"가아그셰블라 분체는 즉시 학회장을 노릴 거고, 본체는 이에 대응할 수밖에 없어요.","JPN":"ガアグシェブラの分体はすぐに学会長を狙うでしょうし、本体はそれに対応するしかありません。","ENG":"The Gha'agsheblah Fragment will immediately target the President, and she will have no choice but to respond.","TWN":"加格舍夫拉的分體會立刻以學會長為目標，而本體也不得不加以應對。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"마치 쳇바퀴가 돌아가듯, 상황은 계속해서 교착 상태에 빠질 겁니다.","JPN":"同じことが繰り返されるだけで、状況は膠着してしまうでしょう。","ENG":"Like a hamster wheel turning, the situation will continue to fall into a stalemate.","TWN":"局勢就會像轉動的齒輪持續陷入僵局。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"소감이 어떠신가요, 종교학부장님?","JPN":"感想はどうですか？　アビゲイル宗教学部長。","ENG":"How does it feel, Dean of Religion?","TWN":"你的感想如何呢，宗教學院院長？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"눈 앞에서 오랫동안 바라던 광경이 연출되고 있는데.","JPN":"目の前にずっと夢に描いていた光景が広がっていますが。","ENG":"A scene you have long desired is unfolding right before your eyes.","TWN":"你長久以來渴望的光景，正在眼前上演。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후후, 확실히 그렇네.","JPN":"ふふ、そうね。","ENG":"Fufu, that's certainly true.","TWN":"呵呵，確實如此。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이대로 소모전을 반복하면, 저 추악한 존재들이 모두 공멸해 버릴지도 모르겠지.","JPN":"このまま消耗戦が続けば、あの忌々しい存在たちが共倒れしてくれるかもね。","ENG":"If this war of attrition keeps repeating, those grotesque beings might all end up destroying each other.","TWN":"如果就這樣反覆進行消耗戰，那些醜陋的存在或許會全部同歸於盡吧。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"하지만 이렇게까지 서비스해주니까, 오히려 궁금한 걸?","JPN":"でも、さすがにここまでサービスされると逆に気になっちゃうわ。","ENG":"But since you're going this far, it actually makes me curious.","TWN":"不過都做到這種地步了，反而讓人好奇呢？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"각본가 양이 구상하고 있는 큰 그림이 말이야.","JPN":"脚本家のお嬢さんの計画が。","ENG":"About the bigger picture you're envisioning, scriptwriter.","TWN":"編劇小姐構想的大局。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"큰 그림이라고요?","JPN":"計画？","ENG":"The bigger picture?","TWN":"大局？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};